var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......그렇게, 내 얘기는 끝이야.","JPN":"……これで、私の話は終わりだ。","ENG":"... And that's how my story ends.","TWN":"……這就是我的故事。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"참 한심하지. 순간의 변덕 때문에 결국 그런 꼴이 되어 버렸다니.","JPN":"実に情けない話だ。一瞬の気の迷いで結局あの有様になってしまうなんて。","ENG":"Pretty pathetic, right? I ended up turning myself into a monster on a whim.","TWN":"很無言吧。因為一瞬間的變化，最終成了這副樣子。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"술자리 얘기로는 끝이 좋지 않군.","JPN":"バーで話すエピソードには向いてないな。","ENG":"I guess this is a bit of a buzzkill for a bar story.","TWN":"作為酒桌上的故事來說，結局不怎麼好呢。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"왜 마지막에 와서 거짓말을 하나?","JPN":"なぜ最後の最後に噓をつくのかね？","ENG":"Why did you lie at the end?","TWN":"妳為什麼最後要說謊？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"왜 그렇게 생각하는 거지? 확신에 찰 만한 근거라도 있나?","JPN":"なぜそう思う？　断言できる根拠でもあるのか？","ENG":"What makes you say that? How can you be so sure?","TWN":"為什麼這麼想？有什麼確鑿的證據嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 그림자로 변이했다는 건 틀림없는 사실일세.","JPN":"君がシャドウに変異したのは間違いない事実だ。","ENG":"You did indeed turn into a Shadow.","TWN":"你變異成為暗影是事實。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"식별명은 미니스트라. 확인된 것만 해도 다섯 명 이상의 카운터를 살해한 위험 개체였지.","JPN":"識別名はミニストラ。確認された記録だけでも5人以上のカウンターを殺害した危険個体だった。","ENG":"Code Name: Ministra. An extremely dangerous specimen confirmed to have slaughtered at least five Counters, possibly many more.","TWN":"識別名「潼恩」。光是目前能確認到的資訊，就是殺害過5名以上制裁者的超危險個體。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리 회사 직원들은 작전 중에 자네를 격퇴하는 데 성공했다네.","JPN":"当社の社員たちは作戦中に君の撃退に成功した。","ENG":"My employees were able to defeat you during a mission.","TWN":"我們公司的職員說在作戰中有成功擊退了你。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 쉬웠다는 뜻은 아니야.","JPN":"しかし簡単な作戦ではなかった。","ENG":"That's not to say it was easy.","TWN":"我並不是想表達很容易的意思。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"몇몇 우연과 행운이 겹치지 않았다면...... 장래 유망한 소대원들을 여러 명 잃을 뻔했지.","JPN":"いくつかの偶然と幸運が重ならなければ、将来有望な小隊員を何人か失うところだった。","ENG":"Without a bit of luck and a series of coincidences... I could have lost many promising operatives that day.","TWN":"因為如果不是一些偶然和幸運的話……差點會因此失去幾個很有前途的小隊員。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"좋아. 이제 와서 나도 못 믿겠다느니 할 생각 없어.","JPN":"いいだろう。今さら私も信じられないなんて言うつもりはない。","ENG":"Fine. I'm not going to bother arguing against any of that at this point.","TWN":"好吧，事到如今我也不會再說我不相信了。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"네 말대로라면 이미 죽었어야 할 내가 여기 있다는 사실이 조금 미심쩍지만.","JPN":"お前の話どおりなら、もう死んでいるはずの私がここにいる理由が疑わしいが。","ENG":"Although I do find it suspicious that I'm not dead, if what you suggested is true.","TWN":"按你所說，我應該已經死了，卻出現這裡，確實有些匪夷所思。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래서, 내 얘기가 거짓말이라고 생각하는 이유는 뭐지?","JPN":"で、私の話が嘘だと思う理由は？","ENG":"So, why do you think I lied anyway?","TWN":"所以，你認為我說謊的理由是什麼？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미니스트라 곁에 빈번하게 출몰하는 그림자가 하나 더 있었어.","JPN":"ミニストラのそばに頻繁に出没するシャドウがもう一体いた。","ENG":"There was one more Shadow that always appeared with Ministra.","TWN":"在迷你斯特拉身邊頻繁出沒的暗影還有一個。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"작전 기록을 확인해 보니 집에 가고 싶다고 울부짖으면서 달려들었다더군.","JPN":"作戦記録によると、家に帰りたいと泣き叫びながら襲いかかっていたそうだね。","ENG":"According to the operations logs, she cried that she wanted to go home as she attacked my employees.","TWN":"確認作戰記錄後，發現那個暗影總是在哭喊著說想回家，就會撲上來。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};